 function getTextFromElement(element) {
   if (element.tagName === 'SCRIPT' || element.tagName === 'STYLE') {
     return '';
   }
   if (element.tagName === 'SELECT' || element.tagName === 'OPTION') {
     return '';
   }
   if (element.tagName === 'A') {
     return element.textContent;
   }
   if (element.tagName === 'INPUT' || element.tagName === 'TEXTAREA') {
     return element.value;
   }
   return element.textContent;
 }

 function getTextFromNode(node) {
   if (node.nodeType === Node.TEXT_NODE) {
     return node.textContent;
   }
   if (node.nodeType === Node.ELEMENT_NODE) {
     return getTextFromElement(node);
   }
   return '';
 }

 function getTextFromNodes(nodes) {
   return nodes.map(getTextFromNode).join(' ');
 }

 function getTextFromDocument(document) {
   return getTextFromNodes(Array.from(document.body.childNodes));
 }

 function getTextFromUrl(url) {
   return fetch(url)
     .then(response => response.text())
     .then(html => {
       const parser = new DOMParser();
       const document = parser.parseFromString(html, 'text/html');
       return getTextFromDocument(document);
     });
 }

 function getTextFromUrls(urls) {
   return Promise.all(urls.map(getTextFromUrl));
 }

 function getTextFromUrlsInParallel(urls) {
   return Promise.all(urls.map(url => getTextFromUrl(url)));
 }

 function getTextFromUrlsInSequence(urls) {
   return urls.reduce((promise, url) => {
     return promise.then(() => getTextFromUrl(url));
   }, Promise.resolve());
 }

 function getTextFromUrlsInBatches(urls, batchSize) {
   const batches = [];
   for (let i = 0; i < urls.length; i += batchSize) {
     batches.push(urls.slice(i, i + batchSize));
   }
   return batches.reduce((promise, batch) => {
     return promise.then(() => getTextFromUrlsInParallel(batch));
   }, Promise.resolve());
 }

 function getTextFromUrlsWithRetry(urls, maxRetries) {
   return urls.map(url => {
     return retry(() => getTextFromUrl(url), maxRetries);
   });
 }

 function retry(fn, maxRetries) {
   return fn().catch(error => {
     if (maxRetries === 0) {
       throw error;
     }
     return retry(fn, maxRetries - 1);
   });
 }

 function getTextFromUrlsWithTimeout(urls, timeout) {
   return urls.map(url => {
     return Promise.race([
       getTextFromUrl(url),
       new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout')), timeout))
     ]);
   });
 }

 function getTextFromUrlsWithProgress(urls) {
   let completed = 0;
   const total = urls.length;
   return Promise.all(urls.map(url => {
     return getTextFromUrl(url).then(text => {
       completed++;
       const progress = (completed / total) * 100;
       console.log(`Progress: ${progress}%`);
       return text;
     });
   }));
 }

 function getTextFromUrlsWithCancellation(urls) {
   const controller = new AbortController();
   const signal = controller.signal;
   return Promise.all(urls.map(url => {
     return fetch(url, { signal }).then(response => response.text());
   }));
 }

 function getTextFromUrlsWithPriority(urls) {
   const priorities = urls.map((_, index) => index);
   const sortedUrls = urls.sort((a, b) => {
     const priorityA = priorities[urls.indexOf(a)];
     const priorityB = priorities[urls.indexOf(b)];
     return priorityA - priorityB;
